query:
-- 1. Listar um corretor específico da Baggio
SELECT id, name, email, role, companyId, managerId FROM users WHERE role = 'broker' AND companyId = (SELECT id FROM companies WHERE name LIKE '%Baggio%' LIMIT 1) LIMIT 1;

-- 2. Listar vendas desse corretor
SELECT id, buyerName, saleValue, brokerVendedor, brokerAngariador, companyId, status FROM sales WHERE brokerVendedor = (SELECT id FROM users WHERE role = 'broker' AND companyId = (SELECT id FROM companies WHERE name LIKE '%Baggio%' LIMIT 1) LIMIT 1) LIMIT 5;

-- 3. Listar comissões desse corretor
SELECT id, brokerId, commissionValue, status, type FROM commissions WHERE brokerId = (SELECT id FROM users WHERE role = 'broker' AND companyId = (SELECT id FROM companies WHERE name LIKE '%Baggio%' LIMIT 1) LIMIT 1) LIMIT 5;

